internal sealed class ScheduledPublishingService : IScheduledPublishingService
{
    private readonly IPostRepository _postRepository;
    private readonly IUnitOfWork _unitOfWork;
    private readonly IClock _clock;
    private readonly IMonetizationRuleEvaluator _monetizationRuleEvaluator;
    private readonly IDomainEventDispatcher _eventDispatcher;
    private readonly IContentSyndicator _contentSyndicator;  // NEW
    private readonly ILogger<ScheduledPublishingService> _logger;

    public ScheduledPublishingService(
        IPostRepository postRepository,
        IUnitOfWork unitOfWork,
        IClock clock,
        IMonetizationRuleEvaluator monetizationRuleEvaluator,
        IDomainEventDispatcher eventDispatcher,
        IContentSyndicator contentSyndicator,  // NEW
        ILogger<ScheduledPublishingService> logger)
    {
        // ... existing null checks
        _contentSyndicator = contentSyndicator ?? throw new ArgumentNullException(nameof(contentSyndicator));
    }

    public async Task<PublishingReport> PromoteDueScheduledPostsAsync(CancellationToken cancellationToken = default)
    {
        // ... existing code to find and process posts

        foreach (var post in duePosts)
        {
            try
            {
                // ... existing monetization check

                post.Publish(_clock.UtcNow);
                await _unitOfWork.SaveChangesAsync(cancellationToken).ConfigureAwait(false);

                // Dispatch domain events
                await _eventDispatcher.DispatchAsync(post.PendingEvents, cancellationToken).ConfigureAwait(false);
                post.ClearPendingEvents();

                // NEW: Syndicate to external aggregator after successful publication
                var syndicationResult = await _contentSyndicator
                    .SyndicateAsync(post, cancellationToken)
                    .ConfigureAwait(false);

                if (!syndicationResult.IsSuccess)
                {
                    _logger.LogWarning(
                        "Content syndication failed for Post {PostId}: {Error}",
                        post.Id, syndicationResult.ErrorMessage);
                    // Note: Syndication failure is non-blocking; post is still published
                }

                published++;
                _logger.LogInformation("Post {PostId} successfully published.", post.Id);
            }
            catch (Exception ex)
            {
                // ... existing error handling
            }
        }
        // ... return report
    }
}
```

