   132→    /// </summary>
   133→    public sealed class MonetizationService
   134→    {
   135→        private readonly IMonetizationRuleRepositoryPort _ruleRepository;
   136→        private readonly IPaymentGatewayPort _paymentGateway;
   137→        private readonly ILogger<MonetizationService> _logger;
   138→
   139→        public MonetizationService(
   140→            IMonetizationRuleRepositoryPort ruleRepository,
   141→            IPaymentGatewayPort paymentGateway,
   142→            ILogger<MonetizationService> logger)
   143→        {
   144→            _ruleRepository = ruleRepository ?? throw new ArgumentNullException(nameof(ruleRepository));
   145→            _paymentGateway = paymentGateway ?? throw new ArgumentNullException(nameof(paymentGateway));
   146→            _logger = logger ?? throw new ArgumentNullException(nameof(logger));
   147→        }
   148→
   149→        /// <summary>
   150→        /// Determines the price a given reader must pay to unlock a post.
   151→        /// </summary>
   152→        /// <remarks>
   153→        /// The method is pure (does not touch the gateway).  Caching adapters
   154→        /// may memoize the result for efficiency.
   155→        /// </remarks>
   156→        public async Task<PriceQuote> QuoteAsync(
   157→            Guid blogId,
   158→            string currency,
   159→            DateTimeOffset at,
   160→            CancellationToken ct = default)
   161→        {
   162→            // 1. Pull active rules
   163→            var rules = await _ruleRepository.GetActiveRulesAsync(blogId, at, ct);
   164→
   165→            if (rules.Count == 0)
   166→            {
   167→                _logger.LogWarning("No active monetization rules found for blog {BlogId}", blogId);
   168→                return new PriceQuote(RuleKind.Free, Money.Zero, currency);
   169→            }
   170→
   171→            // 2. Business rule: prefer the most specific rule by precedence order.
   172→            //    For MVP: PayPerPost > SubscriptionRequired > Free
   173→            var ordered = rules
   174→                .Where(r => r.IsActive(at))
   175→                .OrderBy(r => r.Kind switch
   176→                {
   177→                    RuleKind.PayPerPost        => 1,
   178→                    RuleKind.SubscriptionRequired => 2,
   179→                    RuleKind.Free              => 3,
   180→                    _                          => 99
   181→                })
   182→                .ToList();
   183→
   184→            var selected = ordered.FirstOrDefault();
   185→
   186→            if (selected is null)
   187→            {
   188→                _logger.LogInformation("All rules inactive, treating as Free content for blog {BlogId}", blogId);
   189→                return new PriceQuote(RuleKind.Free, Money.Zero, currency);
   190→            }
   191→
   192→            _logger.LogDebug(
   193→                "Selected monetization rule {RuleId} (Kind {Kind}) for blog {BlogId}",
   194→                selected.Id, selected.Kind, blogId);
   195→
   196→            return new PriceQuote(selected.Kind, selected.Price, currency);
   197→        }
   198→
   199→        /// <summary>
   200→        /// Creates a payment intent and returns the opaque client secret.
   201→        /// </summary>
   202→        /// <exception cref="InvalidOperationException">
   203→        /// Thrown when the quoted price does not match the rule at capture time.
   204→        /// </exception>
   205→        public async Task<PaymentIntent> CreatePaymentIntentAsync(
   206→            Guid blogId,
   207→            string currency,
   208→            string customerId,
   209→            DateTimeOffset at,
   210→            CancellationToken ct = default)
   211→        {
   212→            var quote = await QuoteAsync(blogId, currency, at, ct);
   213→            if (quote.Kind is RuleKind.Free)
   214→            {
   215→                throw new InvalidOperationException("Attempted to create payment intent for a free post.");
   216→            }
   217→
   218→            Money amount = quote.Amount;
   219→            if (amount.Amount <= 0)
   220→            {
   221→                _logger.LogError(
   222→                    "Invalid quote amount {Amount} for blog {BlogId}",
   223→                    amount.Amount, blogId);
   224→                throw new InvalidOperationException("Quoted amount must be positive.");
   225→            }
   226→
   227→            _logger.LogInformation(
   228→                "Creating payment intent for blog {BlogId} customer {CustomerId} amount {Amount} {Currency}",
   229→                blogId, customerId, amount.Amount, currency);
   230→
   231→            try
   232→            {
   233→                var intent = await _paymentGateway.CreatePaymentIntentAsync(
   234→                    amount,
   235→                    currency,
   236→                    customerId,
   237→                    ct);
   238→
   239→                _logger.LogInformation(
   240→                    "Payment intent {IntentId} created for blog {BlogId}",
   241→                    intent.Id, blogId);
   242→
   243→                return intent;
   244→            }
   245→            catch (Exception ex)
   246→            {
   247→                _logger.LogError(ex,
   248→                    "Failed to create payment intent for blog {BlogId} customer {CustomerId}",
   249→                    blogId, customerId);
   250→                throw; // Bubble up – application service can translate.
   251→            }
   252→        }
   253→
   254→        /// <summary>
   255→        /// Captures the previously created payment intent.
   256→        /// </summary>
   257→        public async Task<PaymentReceipt> CaptureAsync(
   258→            Guid intentId,
   259→            CancellationToken ct = default)
   260→        {
   261→            try
   262→            {
   263→                var receipt = await _paymentGateway.CaptureAsync(intentId, ct);
   264→                _logger.LogInformation(
   265→                    "Payment intent {IntentId} captured at {CapturedAt}",
   266→                    intentId, receipt.CapturedAtUtc);
   267→                return receipt;
   268→            }
   269→            catch (Exception ex)
   270→            {
   271→                _logger.LogError(ex,
   272→                    "Failed to capture payment intent {IntentId}",
   273→                    intentId);
   274→                throw;
   275→            }
   276→        }
   277→    }
   278→}
