   131→    /// <inheritdoc />
   132→    public sealed class ScheduledPublishingService : IScheduledPublishingService
   133→    {
   134→        private const string PublishMetric            = "tempo.posts.published.count";
   135→        private const string PublishDurationMetric    = "tempo.posts.publish.duration_ms";
   136→        private static readonly TimeSpan LockTimeout  = TimeSpan.FromSeconds(5);
   137→
   138→        private readonly IPostRepository _postRepository;
   139→        private readonly IDateTimeProvider _clock;
   140→        private readonly INotificationPort _notificationPort;
   141→        private readonly IMetricsPort _metrics;
   142→        private readonly IDistributedLockProvider _lockProvider;
   143→        private readonly ILogger<ScheduledPublishingService> _logger;
   144→        private readonly AsyncRetryPolicy _retryPolicy;
   145→
   146→        public ScheduledPublishingService(
   147→            IPostRepository postRepository,
   148→            IDateTimeProvider clock,
   149→            INotificationPort notificationPort,
   150→            IMetricsPort metrics,
   151→            IDistributedLockProvider lockProvider,
   152→            ILogger<ScheduledPublishingService> logger)
   153→        {
   154→            _postRepository     = postRepository ?? throw new ArgumentNullException(nameof(postRepository));
   155→            _clock              = clock ?? throw new ArgumentNullException(nameof(clock));
   156→            _notificationPort   = notificationPort ?? throw new ArgumentNullException(nameof(notificationPort));
   157→            _metrics            = metrics ?? throw new ArgumentNullException(nameof(metrics));
   158→            _lockProvider       = lockProvider ?? throw new ArgumentNullException(nameof(lockProvider));
   159→            _logger             = logger ?? throw new ArgumentNullException(nameof(logger));
   160→
   161→            // Exponential back-off:  2 retries after 200ms, 800ms
   162→            _retryPolicy = Policy
   163→                .Handle<Exception>()
   164→                .WaitAndRetryAsync(
   165→                    retryCount: 2,
   166→                    sleepDurationProvider: attempt => TimeSpan.FromMilliseconds(200 * Math.Pow(2, attempt)),
   167→                    onRetry: (ex, delay, attempt, ctx) =>
   168→                    {
   169→                        _logger.LogWarning(ex, "Retrying post publication (attempt {Attempt}) after {Delay}", attempt, delay);
   170→                    });
   171→        }
   172→
   173→        /// <summary>
   174→        /// Executes a full publishing pass. Safe to call concurrently; a distributed
   175→        /// lock is taken per post to avoid duplicate work across clustered nodes.
   176→        /// </summary>
   177→        public async Task RunPublishingCycleAsync(CancellationToken cancellationToken = default)
   178→        {
   179→            DateTimeOffset now = _clock.UtcNow;
   180→
   181→            _logger.LogInformation("Running scheduled publishing cycle at {UtcNow}", now);
   182→
   183→            IReadOnlyList<Post> duePosts =
   184→                await _postRepository.GetPostsScheduledUntilAsync(now, cancellationToken)
   185→                                     .ConfigureAwait(false);
   186→
   187→            if (!duePosts.Any())
   188→            {
   189→                _logger.LogDebug("No posts eligible for publication.");
   190→                return;
   191→            }
   192→
   193→            _logger.LogInformation("Found {PostCount} post(s) ready to publish", duePosts.Count);
   194→
   195→            foreach (var post in duePosts)
   196→            {
   197→                // Each post works in its own retry scope to isolate failures
   198→                await _retryPolicy.ExecuteAsync(
   199→                    ct => PublishPostAsync(post, ct),
   200→                    cancellationToken)
   201→                    .ConfigureAwait(false);
   202→            }
   203→
   204→            _logger.LogInformation("Scheduled publishing cycle completed.");
   205→        }
