   207→        private async Task PublishPostAsync(Post post, CancellationToken cancellationToken)
   208→        {
   209→            string lockResource = $"tempo.post.publish.{post.Id}";
   210→
   211→            await using IDistributedLock theLock =
   212→                await _lockProvider.AcquireAsync(lockResource, LockTimeout, cancellationToken)
   213→                                   .ConfigureAwait(false);
   214→
   215→            if (theLock is null)
   216→            {
   217→                _logger.LogWarning("Skipped publishing post {PostId} because lock '{Lock}' is held by another instance.",
   218→                    post.Id, lockResource);
   219→                return;
   220→            }
   221→
   222→            if (!post.IsReadyForPublication(_clock))
   223→            {
   224→                _logger.LogDebug("Post {PostId} is not eligible for publication anymore. Maybe processed in prior pass.",
   225→                    post.Id);
   226→                return;
   227→            }
   228→
   229→            var stopwatch = System.Diagnostics.Stopwatch.StartNew();
   230→
   231→            try
   232→            {
   233→                _logger.LogInformation("Publishing post {PostId}", post.Id);
   234→
   235→                post.Publish(_clock);
   236→
   237→                await _postRepository.UpdateAsync(post, cancellationToken)
   238→                                     .ConfigureAwait(false);
   239→
   240→                await _notificationPort.NotifyPostPublishedAsync(post, cancellationToken)
   241→                                       .ConfigureAwait(false);
   242→
   243→                _metrics.Increment(PublishMetric);
   244→
   245→                stopwatch.Stop();
