    55→        /// <inheritdoc />
    56→        public async Task<int> ProcessScheduledPublishingAsync(CancellationToken cancellationToken = default)
    57→        {
    58→            // STEP 1: Fetch posts that are READY to be published.
    59→            IReadOnlyCollection<Post> duePosts;
    60→            var asOf = _dateTimeProvider.UtcNow;
    61→
    62→            try
    63→            {
    64→                duePosts = await _postRepository
    65→                    .GetScheduledPostsDueAsync(asOf, cancellationToken)
    66→                    .ConfigureAwait(false);
    67→            }
    68→            catch (Exception ex)
    69→            {
    70→                _logger.LogError(ex,
    71→                    "Failed to query scheduled posts due as of {AsOf:u}", asOf);
    72→                throw new PublishingAutomationException(
    73→                    "Failed to query scheduled posts due.", ex);
    74→            }
    75→
    76→            if (duePosts.Count == 0)
    77→            {
    78→                _logger.LogDebug("No scheduled posts were due as of {AsOf:u}", asOf);
    79→                return 0;
    80→            }
    81→
    82→            _logger.LogInformation("Found {Count} scheduled post(s) due for publishing.", duePosts.Count);
    83→
    84→            // STEP 2: Iterate and publish each post atomically.
    85→            var publishedCount = 0;
    86→
    87→            foreach (var post in duePosts)
    88→            {
    89→                cancellationToken.ThrowIfCancellationRequested();
    90→
    91→                if (!post.CanBePublished())
    92→                {
    93→                    _logger.LogWarning("Post {PostId} was returned as scheduled but cannot be published due to state {State}.",
    94→                        post.Id, post.Status);
    95→                    continue;
    96→                }
    97→
    98→                try
    99→                {
   100→                    PublishPostDomainLogic(post, asOf);
   101→
   102→                    await _postRepository
   103→                        .UpdateAsync(post, cancellationToken)
   104→                        .ConfigureAwait(false);
   105→
   106→                    await _eventPublisher
   107→                        .PublishAsync(new ScheduledPostPublishedEvent(post.Id, post.Slug, post.PublishedUtc!.Value))
   108→                        .ConfigureAwait(false);
   109→
   110→                    publishedCount++;
   111→                    _logger.LogInformation("Successfully published Post {PostId}.", post.Id);
   112→                }
   113→                catch (ConcurrencyException ex)
   114→                {
   115→                    // Another worker beat us to it—log at debug and move on.
   116→                    _logger.LogDebug(ex,
   117→                        "Concurrency conflict encountered while publishing Post {PostId}. " +
   118→                        "It was likely published by another process.", post.Id);
   119→                }
   120→                catch (Exception ex)
   121→                {
   122→                    // We keep looping instead of failing the entire batch, but bubble-up at the end.
   123→                    _logger.LogError(ex,
   124→                        "Unexpected error occurred while publishing Post {PostId}.", post.Id);
   125→                    throw new PublishingAutomationException(
   126→                        $"Failed to publish Post {post.Id}.", ex);
   127→                }
   128→            }
   129→
   130→            _logger.LogInformation("Publishing automation completed. {PublishedCount} post(s) published.", publishedCount);
   131→            return publishedCount;
   132→        }
