   207→            DateTimeOffset threshold = _clock.UtcNow;
   208→
   209→            IReadOnlyCollection<Post> candidates;
   210→            try
   211→            {
   212→                candidates = await _postRepo.FindScheduledBeforeAsync(threshold, DefaultBatchSize, ct);
   213→            }
   214→            catch (Exception dbEx)
   215→            {
   216→                _logger.LogError(dbEx, "Failed to retrieve scheduled posts.");
   217→                throw new ScheduledPublishFailureException("Database read failure.", dbEx);
   218→            }
   219→
   220→            if (candidates.Count == 0)
   221→            {
   222→                _logger.LogInformation("No posts eligible for publishing at this time.");
   223→                return;
   224→            }
   225→
   226→            _logger.LogInformation("Found {Count} post(s) scheduled for publishing.", candidates.Count);
   227→
   228→            foreach (var post in candidates)
   229→            {
   230→                // Publish each post in isolation so failure of one does not cancel the entire batch
   231→                bool success = await PublishWithRetriesAsync(post, ct);
   232→                if (!success)
   233→                {
