   241→        private async Task<bool> PublishWithRetriesAsync(Post post, CancellationToken ct)
   242→        {
   243→            for (int attempt = 1; attempt <= MaxRetryAttempts; attempt++)
   244→            {
   245→                try
   246→                {
   247→                    await PublishPostAsync(post, ct);
   248→                    return true;
   249→                }
   250→                catch (InvalidPostStateException invalidEx)
   251→                {
   252→                    // Invariant violation – there is no point retrying
