   254→                        "Invariant violation while publishing post {PostId}. Skipping retry.",
   255→                        post.Id);
   256→                    return false;
   257→                }
   258→                catch (Exception ex) when (attempt < MaxRetryAttempts)
   259→                {
   260→                    _logger.LogWarning(ex,
   261→                        "Attempt {Attempt} failed for post {PostId}. Retrying...",
   262→                        attempt, post.Id);
   263→
   264→                    await Task.Delay(TimeSpan.FromMilliseconds(200 * attempt), ct);
   265→                }
   266→                catch (Exception finalEx)
   267→                {
   268→                    _logger.LogError(finalEx,
   269→                        "Final attempt failed for post {PostId}. Giving up.",
   270→                        post.Id);
   271→                    return false;
   272→                }
   273→            }
   274→
   275→            return false;
   276→        }
   277→
   278→        /// <summary>
   279→        /// Publishes a single post inside a transactional boundary.
   280→        /// </summary>
   281→        private async Task PublishPostAsync(Post post, CancellationToken ct)
   282→        {
   283→            _logger.LogDebug("Publishing post {PostId}", post.Id);
   284→
   285→            post.Publish(_clock.UtcNow);
   286→
   287→            try
   288→            {
   289→                await _postRepo.UpdateAsync(post, ct);
