   106→    /// <summary>
   107→    /// Quartz implementation of the publication scheduler.
   108→    /// Respects the IPostPublicationScheduler port, enabling painless swapping.
   109→    /// </summary>
   110→    public sealed class QuartzPublicationSchedulerAdapter : IPostPublicationScheduler, IAsyncDisposable
   111→    {
   112→        private const string JobGroup   = "TempoScribePro.PostPublishing";
   113→        private const string TriggerGrp = "TempoScribePro.PublishTriggers";
   114→
   115→        private readonly IScheduler               _scheduler;
   116→        private readonly ILogger<QuartzPublicationSchedulerAdapter> _logger;
   117→
   118→        public QuartzPublicationSchedulerAdapter(IScheduler scheduler,
   119→                                                 ILogger<QuartzPublicationSchedulerAdapter> logger)
   120→        {
   121→            _scheduler = scheduler ?? throw new ArgumentNullException(nameof(scheduler));
   122→            _logger    = logger    ?? throw new ArgumentNullException(nameof(logger));
   123→        }
   124→
   125→        #region IPostPublicationScheduler
   126→
   127→        public async Task ScheduleAsync(ScheduledPost post, CancellationToken ct = default)
   128→        {
   129→            if (post == null) throw new ArgumentNullException(nameof(post));
   130→
   131→            ct.ThrowIfCancellationRequested();
   132→
   133→            var jobKey = CreateJobKey(post.Id);
   134→            if (await _scheduler.CheckExists(jobKey, ct))
   135→            {
   136→                // Replace existing schedule (idempotent behaviour)
   137→                await CancelAsync(post.Id, ct);
   138→            }
   139→
   140→            var job = JobBuilder
   141→                .Create<PublishPostJob>()
   142→                .WithIdentity(jobKey)
   143→                .UsingJobData(nameof(ScheduledPost.Id),        post.Id.ToString())
   144→                .UsingJobData(nameof(ScheduledPost.AuthorId),  post.AuthorId.ToString())
   145→                .UsingJobData(nameof(ScheduledPost.Title),     post.Title)
   146→                .Build();
   147→
   148→            var trigger = TriggerBuilder
   149→                .Create()
   150→                .WithIdentity(CreateTriggerKey(post.Id))
   151→                .StartAt(post.PublishAtUtc.UtcDateTime)
   152→                .WithSimpleSchedule(x => x.WithMisfireHandlingInstructionFireNow())
   153→                .ForJob(job)
   154→                .Build();
   155→
   156→            await _scheduler.ScheduleJob(job, trigger, ct);
   157→
   158→            _logger.LogInformation("Scheduled post '{Title}' (Id: {Id}) for {PublishAt}.",
   159→                                   post.Title, post.Id, post.PublishAtUtc);
   160→        }
   161→
   162→        public async Task<bool> CancelAsync(Guid postId, CancellationToken ct = default)
   163→        {
   164→            if (postId == Guid.Empty) throw new ArgumentException("Post id cannot be empty.", nameof(postId));
   165→
   166→            ct.ThrowIfCancellationRequested();
   167→
   168→            var jobKey = CreateJobKey(postId);
   169→            var deleted = await _scheduler.DeleteJob(jobKey, ct);
   170→
   171→            if (deleted)
   172→                _logger.LogInformation("Cancelled scheduled publication for PostId {PostId}.", postId);
   173→            else
   174→                _logger.LogWarning("Attempted to cancel non-existent schedule for PostId {PostId}.", postId);
   175→
   176→            return deleted;
   177→        }
