   156→    /// <summary>
   157→    /// Orchestrates scheduled publishing for posts that are due.
   158→    /// Intended to be executed by a hosted background worker or a serverless job.
   159→    /// </summary>
   160→    public sealed class ScheduledPublishingService
   161→    {
   162→        private const string CacheKeyPrefix     = "scheduler:next:";
   163→        private readonly IPostRepository        _repository;
   164→        private readonly IPaymentGateway        _paymentGateway;
   165→        private readonly ICacheAdapter          _cache;
   166→        private readonly IClock                 _clock;
   167→        private readonly IEventBus              _eventBus;
   168→        private readonly ILogger                _logger;
