   171→
   172→        public ScheduledPublishingService(
   173→            IPostRepository repository,
   174→            IPaymentGateway paymentGateway,
   175→            ICacheAdapter cache,
   176→            IClock clock,
   177→            IEventBus eventBus,
   178→            ILogger<ScheduledPublishingService> logger,
