   182→            _paymentGateway = paymentGateway ?? throw new ArgumentNullException(nameof(paymentGateway));
   183→            _cache          = cache       ?? throw new ArgumentNullException(nameof(cache));
   184→            _clock          = clock       ?? throw new ArgumentNullException(nameof(clock));
   185→            _eventBus       = eventBus    ?? throw new ArgumentNullException(nameof(eventBus));
   186→            _logger         = logger      ?? throw new ArgumentNullException(nameof(logger));
