   190→        /// <summary>
   191→        /// Publishes every post that has reached its scheduled time.
   192→        /// Returns number of posts successfully published.
   193→        /// </summary>
   194→        public async Task<int> PublishDuePostsAsync(CancellationToken ct = default)
   195→        {
   196→            // Ensures single execution at a time even if the job is triggered in parallel.
   197→            if (!await _mutex.WaitAsync(TimeSpan.Zero, ct))
   198→            {
   199→                _logger.LogDebug("Scheduler is already running – skipping concurrent execution.");
   200→                return 0;
   201→            }
   202→
   203→            try
   204→            {
   205→                var now      = _clock.UtcNow;
   206→                var cacheKey = CacheKeyPrefix + now.UtcDateTime.ToString("yyyyMMddHHmm");
   207→
   208→                // Attempt to pull scheduled posts from the cache first.
   209→                var duePosts = await _cache.GetAsync<IReadOnlyList<Post>>(cacheKey, ct)
   210→                               ?? await FetchAndCacheAsync(cacheKey, now, ct);
   211→
   212→                if (duePosts.Count == 0)
   213→                {
   214→                    _logger.LogTrace("No posts due for publication at {Time}.", now);
   215→                    return 0;
   216→                }
   217→
   218→                int publishedCount = 0;
   219→                foreach (var post in duePosts.Where(p => p.Status == PostStatus.Scheduled))
   220→                {
   221→                    try
   222→                    {
   223→                        ct.ThrowIfCancellationRequested();
   224→
   225→                        _logger.LogInformation(
   226→                            "Publishing post {PostId} (Premium:{IsPremium}).", post.Id, post.IsPremium);
   227→
   228→                        // Place premium post behind a pay wall first.
   229→                        if (post.IsPremium)
   230→                        {
   231→                            await _paymentGateway.EnsurePayWallAsync(post, ct);
   232→                            _logger.LogDebug("Paywall configured for post {PostId}.", post.Id);
   233→                        }
   234→
   235→                        post.Publish(_clock);
   236→
   237→                        await _repository.SaveAsync(post, ct);
   238→                        await EmitEventsAsync(post, ct);
   239→
   240→                        publishedCount++;
   241→                    }
   242→                    catch (Exception ex)
   243→                    {
   244→                        _logger.LogError(ex,
   245→                            "Error while publishing post {PostId}. Marking as failed.", post.Id);
