   247→                        post.MarkFailed(ex.Message, _clock);
   248→                        await _repository.SaveAsync(post, ct);
   249→                        await EmitEventsAsync(post, ct);
   250→                    }
   251→                }
   252→
   253→                _logger.LogInformation("Scheduler successfully published {Count} posts.", publishedCount);
