   262→        private async Task<IReadOnlyList<Post>> FetchAndCacheAsync(
   263→            string cacheKey,
   264→            DateTimeOffset now,
   265→            CancellationToken ct)
   266→        {
   267→            // Look ahead to reduce DB hits for near-future runs.
   268→            var horizon = now + _lookAhead;
