   296→
   297→        public Task<T?> GetAsync<T>(string key, CancellationToken ct)
   298→        {
   299→            if (_store.TryGetValue(key, out var entry) && !entry.IsExpired)
   300→                return Task.FromResult((T?)entry.Value);
   301→
   302→            _store.TryRemove(key, out _);
   303→            return Task.FromResult(default(T));
   304→        }
   305→
   306→        public Task SetAsync<T>(string key, T value, TimeSpan ttl, CancellationToken ct)
   307→        {
   308→            var expires = DateTimeOffset.UtcNow + ttl;
   309→            _store[key] = new CacheEntry(value!, expires);
   310→            return Task.CompletedTask;
   311→        }
   312→
   313→        private sealed class CacheEntry
   314→        {
   315→            public object Value { get; }
   316→            private readonly DateTimeOffset _expiresAt;
   317→
   318→            public bool IsExpired => DateTimeOffset.UtcNow >= _expiresAt;
   319→
   320→            public CacheEntry(object value, DateTimeOffset expiresAt)
   321→            {
   322→                Value       = value;
   323→                _expiresAt  = expiresAt;
   324→            }
   325→        }
   326→    }
