    51→
    52→            string cacheKey = BuildCacheKey(userId, range);
    53→
    54→            // 1. Happy path: try the cache first
    55→            var cached = await _cache.GetAsync<ProductivitySummaryDto>(cacheKey, cancellationToken);
    56→            if (cached is not null)
    57→            {
    58→                _logger.Debug($"Cache hit for {cacheKey}");
    59→                return cached;
    60→            }
    61→
    62→            // 2. Fetch events from the repository
    63→            IReadOnlyList<EditorialAnalyticsEvent> events;
    64→            try
    65→            {
    66→                events = await _eventRepository.GetEventsAsync(userId, range, cancellationToken);
    67→            }
