   103→    /// <summary>
   104→    /// Coordinates repositories, diff generation, and caching to return
   105→    /// an HTML diff that front-end clients can render instantly.
   106→    /// </summary>
   107→    internal sealed class LivePreviewService : ILivePreviewService
   108→    {
   109→        private const int DefaultCacheMinutes = 10;
   110→
   111→        private readonly IPostReadRepository _postRepo;
   112→        private readonly IDiffGenerator _diffGenerator;
   113→        private readonly IDiffCache _diffCache;
   114→        private readonly ILogger<LivePreviewService> _logger;
   115→
   116→        public LivePreviewService(
   117→            IPostReadRepository postRepo,
   118→            IDiffGenerator diffGenerator,
   119→            IDiffCache diffCache,
   120→            ILogger<LivePreviewService> logger)
   121→        {
   122→            _postRepo      = postRepo  ?? throw new ArgumentNullException(nameof(postRepo));
   123→            _diffGenerator = diffGenerator ?? throw new ArgumentNullException(nameof(diffGenerator));
   124→            _diffCache     = diffCache ?? throw new ArgumentNullException(nameof(diffCache));
   125→            _logger        = logger ?? throw new ArgumentNullException(nameof(logger));
   126→        }
   127→
   128→        public async Task<LivePreviewDto> GetLivePreviewAsync(Guid postId, CancellationToken ct = default)
   129→        {
   130→            // 1. Fetch the latest draft metadata.
   131→            var (draftMarkdown, draftUpdatedUtc) = await _postRepo.FetchLatestDraftMarkdownAsync(postId, ct);
   132→
   133→            // 2. Try to find a cached diff keyed by the draft's last update timestamp.
   134→            string? cachedDiff = await _diffCache.TryGetAsync(postId, draftUpdatedUtc, ct);
   135→            if (cachedDiff is not null)
   136→            {
   137→                _logger.LogDebug("Live preview diff served from cache for Post {PostId}", postId);
   138→                return new LivePreviewDto(postId, cachedDiff, DateTime.UtcNow, true);
   139→            }
   140→
   141→            // 3. Obtain the published text (may be null if unpublished).
   142→            string? publishedMarkdown = await _postRepo.FetchPublishedMarkdownAsync(postId, ct);
   143→
   144→            // 4. Generate a fresh diff.
   145→            string diffHtml;
   146→            try
   147→            {
   148→                diffHtml = await _diffGenerator.GenerateDiffHtmlAsync(publishedMarkdown, draftMarkdown, ct);
   149→            }
   150→            catch (Exception ex)
   151→            {
   152→                _logger.LogError(ex, "Diff generation failed for Post {PostId}", postId);
   153→                throw; // let higher levels decide how to surface to the user
   154→            }
   155→
   156→            // 5. Store it in the distributed cache.
   157→            try
   158→            {
   159→                await _diffCache.CacheAsync(postId, draftUpdatedUtc, diffHtml, ct);
   160→            }
   161→            catch (Exception ex)
   162→            {
   163→                // Cache failures must not break user flow.
   164→                _logger.LogWarning(ex, "Unable to cache diff for Post {PostId}", postId);
   165→            }
   166→
   167→            return new LivePreviewDto(postId, diffHtml, DateTime.UtcNow, false);
   168→        }
   169→    }
