   173→    #region Infrastructure – Diff Cache (Redis / IDistributedCache)
   174→
   175→    /// <summary>
   176→    /// Distributes diff payloads via ASP.NET Core's <see cref="IDistributedCache"/>.
   177→    /// Compatible with Redis, SQL Server, NCache, or any custom provider configured in Startup.
   178→    /// </summary>
   179→    public sealed class DistributedDiffCache : IDiffCache
   180→    {
   181→        private readonly IDistributedCache _cache;
   182→        private readonly ILogger<DistributedDiffCache> _logger;
   183→        private readonly DistributedCacheEntryOptions _entryOptions;
   184→
   185→        public DistributedDiffCache(
   186→            IDistributedCache cache,
   187→            ILogger<DistributedDiffCache> logger,
   188→            int absoluteExpirationMinutes = 20)
   189→        {
   190→            _cache  = cache  ?? throw new ArgumentNullException(nameof(cache));
   191→            _logger = logger ?? throw new ArgumentNullException(nameof(logger));
   192→
   193→            // Configure TTL for diff items. Live previews are short-lived.
   194→            _entryOptions = new DistributedCacheEntryOptions
   195→            {
   196→                AbsoluteExpirationRelativeToNow = TimeSpan.FromMinutes(absoluteExpirationMinutes),
   197→                SlidingExpiration = TimeSpan.FromMinutes(Math.Max(absoluteExpirationMinutes / 2, 5))
   198→            };
   199→        }
   200→
   201→        public async Task CacheAsync(Guid postId, DateTime draftUpdatedUtc, string diffHtml, CancellationToken ct = default)
   202→        {
   203→            var key = BuildKey(postId, draftUpdatedUtc);
   204→            var payload = new DiffCachePayload(diffHtml);
   205→
   206→            await _cache.SetStringAsync(key, JsonConvert.SerializeObject(payload), _entryOptions, ct);
   207→            _logger.LogTrace("Cached diff for Post {PostId} (key={Key})", postId, key);
   208→        }
   209→
   210→        public async Task<string?> TryGetAsync(Guid postId, DateTime draftUpdatedUtc, CancellationToken ct = default)
   211→        {
   212→            var key = BuildKey(postId, draftUpdatedUtc);
   213→            var json = await _cache.GetStringAsync(key, ct);
   214→
   215→            if (json == null)
   216→            {
   217→                return null;
   218→            }
   219→
   220→            try
   221→            {
   222→                var payload = JsonConvert.DeserializeObject<DiffCachePayload>(json);
   223→                return payload?.DiffHtml;
   224→            }
   225→            catch (JsonException ex)
   226→            {
   227→                _logger.LogWarning(ex, "Corrupted diff cache entry detected (key={Key}) – purging.", key);
   228→                await _cache.RemoveAsync(key, ct);
   229→                return null;
   230→            }
   231→        }
   232→
   233→        private static string BuildKey(Guid postId, DateTime updatedUtc)
   234→            => $"livepreview:{postId:N}:{updatedUtc:yyyyMMddHHmmssffff}";
   235→
   236→        private sealed record DiffCachePayload(string DiffHtml);
   237→    }
