   241→    #region Infrastructure – Simple Html Diff Generator
   242→
   243→    /// <summary>
   244→    /// A basic diff generator that operates on Markdown input and highlights line-level changes.
   245→    /// Replace with a more sophisticated semantic diff (e.g. using diff-match-patch) as needed.
   246→    /// </summary>
   247→    public sealed class SimpleHtmlDiffGenerator : IDiffGenerator
   248→    {
   249→        public Task<string> GenerateDiffHtmlAsync(string? oldMarkdown, string newMarkdown, CancellationToken ct = default)
   250→        {
   251→            // For demonstration, compute a naïve line-by-line diff and wrap changes in <ins>/<del>.
   252→            var oldLines = (oldMarkdown ?? string.Empty).Split('\n');
   253→            var newLines = newMarkdown.Split('\n');
   254→
   255→            var diffBuilder = new StringBuilder();
   256→            var max = Math.Max(oldLines.Length, newLines.Length);
   257→
   258→            for (int i = 0; i < max; i++)
   259→            {
   260→                ct.ThrowIfCancellationRequested();
   261→
   262→                var oldLine = i < oldLines.Length ? oldLines[i] : null;
   263→                var newLine = i < newLines.Length ? newLines[i] : null;
   264→
   265→                if (oldLine == newLine)
   266→                {
   267→                    diffBuilder.AppendLine(System.Web.HttpUtility.HtmlEncode(newLine ?? string.Empty));
   268→                }
   269→                else
   270→                {
   271→                    if (oldLine is not null)
   272→                    {
   273→                        diffBuilder.Append("<del class=\"ts-diff-del\">")
   274→                                   .Append(System.Web.HttpUtility.HtmlEncode(oldLine))
   275→                                   .AppendLine("</del>");
   276→                    }
   277→
   278→                    if (newLine is not null)
   279→                    {
   280→                        diffBuilder.Append("<ins class=\"ts-diff-ins\">")
   281→                                   .Append(System.Web.HttpUtility.HtmlEncode(newLine))
   282→                                   .AppendLine("</ins>");
   283→                    }
   284→                }
   285→            }
   286→
   287→            // Wrap in a container so styling can be applied by the front-end.
   288→            var html = $"<div class=\"ts-diff\">{diffBuilder}</div>";
   289→            return Task.FromResult(html);
   290→        }
   291→    }
