    31→    internal sealed class EditorialAnalyticsService : IEditorialAnalyticsService
    32→    {
    33→        private const string CachePrefix = "analytics:editorial-efficiency:";
    34→        private static readonly TimeSpan DefaultCacheTtl = TimeSpan.FromMinutes(15);
