    53→        /// <inheritdoc/>
    54→        public async Task<EditorialEfficiencyReport> GetEfficiencyReportAsync(
    55→            DateTime fromUtc,
    56→            DateTime toUtc,
    57→            CancellationToken cancellationToken = default)
    58→        {
    59→            if (fromUtc > toUtc)
    60→            {
    61→                throw new ValidationException("'fromUtc' cannot be after 'toUtc'.");
    62→            }
    63→
    64→            var cacheKey = BuildCacheKey(fromUtc, toUtc);
    65→
    66→            // 1. Try fast-path: return cached report if available.
    67→            if (await _cache.TryGetAsync<EditorialEfficiencyReport>(cacheKey, cancellationToken) is { } cached)
    68→            {
    69→                _logger.Trace($"Cache hit for analytics report [{cacheKey}].");
    70→                return cached;
    71→            }
    72→
    73→            // 2. Fallback: compute report by projecting events.
    74→            _logger.Info($"Cache miss for analytics report [{cacheKey}] – recomputing.");
    75→
    76→            var events = await _eventStream
    77→                .ReadAsync(fromUtc, toUtc, cancellationToken)
    78→                .ConfigureAwait(false);
    79→
    80→            var report = ComputeReport(events, fromUtc, toUtc);
    81→
    82→            // 3. Persist summary for historic querying (CQRS read-model).
    83→            await _repository.UpsertAsync(report, cancellationToken);
    84→
    85→            // 4. Cache for subsequent reads.
    86→            await _cache.SetAsync(cacheKey, report, DefaultCacheTtl, cancellationToken);
    87→
    88→            return report;
    89→        }
