    98→        private static EditorialEfficiencyReport ComputeReport(
    99→            IEnumerable<IEditorialEvent> events,
   100→            DateTime fromUtc,
   101→            DateTime toUtc)
   102→        {
   103→            // We rely on LINQ for in-memory projection because event counts per
   104→            // timeframe are modest (<100k). For larger volumes consider
   105→            // incremental snapshots or Map-Reduce.
   106→            var groupedByPost = events
   107→                .GroupBy(e => e.PostId)
   108→                .ToArray();
   109→
   110→            int totalPostsPublished = 0;
   111→            double avgDraftIterations = 0;
   112→            double avgTimeToPublishMinutes = 0;
   113→            int totalWordsProduced = 0;
   114→
   115→            foreach (var postEvents in groupedByPost)
   116→            {
   117→                var drafts = postEvents
   118→                    .Where(e => e is DraftUpdatedEvent)
   119→                    .Cast<DraftUpdatedEvent>()
   120→                    .OrderBy(e => e.UtcTimestamp)
   121→                    .ToList();
   122→
   123→                var published = postEvents
   124→                    .FirstOrDefault(e => e is PostPublishedEvent) as PostPublishedEvent;
   125→
   126→                if (published != null)
   127→                {
   128→                    totalPostsPublished++;
   129→
   130→                    if (drafts.Count > 0)
   131→                    {
   132→                        avgDraftIterations += drafts.Count;
   133→                        avgTimeToPublishMinutes +=
   134→                            (published.UtcTimestamp - drafts.First().UtcTimestamp).TotalMinutes;
   135→                    }
   136→
   137→                    totalWordsProduced += published.WordCount;
   138→                }
   139→            }
   140→
   141→            if (totalPostsPublished > 0)
   142→            {
   143→                avgDraftIterations /= totalPostsPublished;
   144→                avgTimeToPublishMinutes /= totalPostsPublished;
   145→            }
   146→
   147→            return new EditorialEfficiencyReport
   148→            (
   149→                ReportId: Guid.NewGuid(),
   150→                From: fromUtc,
   151→                To: toUtc,
   152→                TotalPostsPublished: totalPostsPublished,
   153→                AverageDraftIterations: Math.Round(avgDraftIterations, 2),
   154→                AverageMinutesToPublish: Math.Round(avgTimeToPublishMinutes, 2),
   155→                TotalWordsProduced: totalWordsProduced,
   156→                GeneratedAtUtc: DateTime.UtcNow
   157→            );
   158→        }
   159→    }
