    24→namespace TempoScribePro.Application.Diagnostics
    25→{
    26→    /// <summary>
    27→    /// Immutable value object containing all metrics captured
    28→    /// during a performance snapshot.
    29→    /// </summary>
    30→    public sealed record PerformanceSnapshot
    31→    {
    32→        public DateTimeOffset CapturedAt { get; init; }
    33→        public double CacheHitRatio { get; init; }
    34→        public long CacheSizeBytes { get; init; }
    35→        public TimeSpan DatabaseRoundTripTime { get; init; }
