    41→    /// <summary>
    42→    /// Service port for taking one-click snapshots that can later be
    43→    /// visualised in the admin panel or exported for auditing.
    44→    /// </summary>
    45→    public interface IPerformanceSnapshotService
    46→    {
    47→        Task<PerformanceSnapshot> CaptureAsync(CancellationToken cancellationToken = default);
    48→    }
    49→
    50→    /// <summary>
    51→    /// Adapter-independent contract for retrieving cache statistics.
    52→    /// </summary>
    53→    public interface ICacheStatisticsProvider
    54→    {
    55→        Task<(double hitRatio, long sizeBytes)> GetStatisticsAsync(CancellationToken cancellationToken = default);
    56→    }
    57→
    58→    /// <summary>
    59→    /// Adapter-independent contract for measuring DB latency.
    60→    /// </summary>
    61→    public interface IDatabaseHealthChecker
    62→    {
    63→        Task<TimeSpan> MeasureLatencyAsync(CancellationToken cancellationToken = default);
    64→    }
    65→
    66→    /// <summary>
    67→    /// Adapter-independent contract for verifying payment gateway status.
