    74→    /// <summary>
    75→    /// Orchestrates multiple health check providers and packages the
    76→    /// results into a <see cref="PerformanceSnapshot"/>.
    77→    /// </summary>
    78→    public sealed class PerformanceSnapshotService : IPerformanceSnapshotService
    79→    {
    80→        private readonly ICacheStatisticsProvider         _cacheStats;
    81→        private readonly IDatabaseHealthChecker           _dbHealth;
    82→        private readonly IPaymentGatewayHealthChecker     _paymentHealth;
    83→        private readonly ILogger<PerformanceSnapshotService> _logger;
    84→
    85→        public PerformanceSnapshotService(
    86→            ICacheStatisticsProvider         cacheStats,
    87→            IDatabaseHealthChecker           dbHealth,
    88→            IPaymentGatewayHealthChecker     paymentHealth,
    89→            ILogger<PerformanceSnapshotService> logger)
    90→        {
    91→            _cacheStats    = cacheStats    ?? throw new ArgumentNullException(nameof(cacheStats));
    92→            _dbHealth      = dbHealth      ?? throw new ArgumentNullException(nameof(dbHealth));
    93→            _paymentHealth = paymentHealth ?? throw new ArgumentNullException(nameof(paymentHealth));
    94→            _logger        = logger        ?? throw new ArgumentNullException(nameof(logger));
    95→        }
    96→
    97→        public async Task<PerformanceSnapshot> CaptureAsync(CancellationToken cancellationToken = default)
    98→        {
    99→            using var scope = _logger.BeginScope("Capturing performance snapshot");
   100→
   101→            try
   102→            {
   103→                _logger.LogInformation("Collecting cache statistics…");
   104→                var (hitRatio, cacheSize) = await _cacheStats.GetStatisticsAsync(cancellationToken)
   105→                                                            .ConfigureAwait(false);
   106→
   107→                _logger.LogInformation("Measuring database latency…");
   108→                var dbLatency = await _dbHealth.MeasureLatencyAsync(cancellationToken)
   109→                                               .ConfigureAwait(false);
   110→
   111→                _logger.LogInformation("Checking payment gateway health…");
   112→                var paymentHealthy = await _paymentHealth.IsHealthyAsync(cancellationToken)
   113→                                                         .ConfigureAwait(false);
   114→
   115→                var snapshot = new PerformanceSnapshot
   116→                {
   117→                    CapturedAt              = DateTimeOffset.UtcNow,
   118→                    CacheHitRatio           = hitRatio,
   119→                    CacheSizeBytes          = cacheSize,
   120→                    DatabaseRoundTripTime   = dbLatency,
   121→                    PaymentGatewayHealthy   = paymentHealthy
   122→                };
   123→
   124→                _logger.LogInformation("Performance snapshot captured: {@Snapshot}", snapshot);
   125→                return snapshot;
   126→            }
   127→            catch (Exception ex) when (!ex.IsFatal())
   128→            {
   129→                _logger.LogError(ex, "An error occurred while creating performance snapshot");
   130→                throw;
   131→            }
   132→        }
   133→    }
