   135→    /// <summary>
   136→    /// Basic IMemoryCache based implementation used in non-distributed scenarios.
   137→    /// Relies on custom counters maintained by <see cref="CachingPostRepositoryDecorator"/>.
   138→    /// </summary>
   139→    public sealed class MemoryCacheStatisticsProvider : ICacheStatisticsProvider
   140→    {
   141→        private readonly IMemoryCache _cache;
   142→
   143→        public MemoryCacheStatisticsProvider(IMemoryCache cache)
   144→            => _cache = cache ?? throw new ArgumentNullException(nameof(cache));
   145→
   146→        public Task<(double hitRatio, long sizeBytes)> GetStatisticsAsync(
   147→            CancellationToken cancellationToken = default)
   148→        {
   149→            _cache.TryGetValue(CacheMetricsKeys.HitCounter,   out long hits);
   150→            _cache.TryGetValue(CacheMetricsKeys.MissCounter,  out long misses);
   151→            _cache.TryGetValue(CacheMetricsKeys.SizeBytes,    out long sizeBytes);
   152→
   153→            double ratio = hits + misses == 0 ? 1.0 : (double)hits / (hits + misses);
   154→            return Task.FromResult((ratio, sizeBytes));
   155→        }
   156→    }
   157→
   158→    /// <summary>
   159→    /// Decorator that adds in-process caching to any <see cref="IPostRepository"/>.
   160→    /// Cache entries are automatically invalidated on save/delete and
   161→    /// global metrics are exposed for analytics.
   162→    /// </summary>
   163→    public sealed class CachingPostRepositoryDecorator : IPostRepository
   164→    {
   165→        private readonly IPostRepository _inner;
   166→        private readonly IMemoryCache    _cache;
   167→        private readonly ILogger<CachingPostRepositoryDecorator> _logger;
   168→        private readonly MemoryCacheEntryOptions _cacheOptions;
   169→
   170→        private const string CachePrefix = "post_";
   171→
   172→        public CachingPostRepositoryDecorator(
   173→            IPostRepository inner,
   174→            IMemoryCache cache,
   175→            ILogger<CachingPostRepositoryDecorator> logger,
   176→            TimeSpan? absoluteExpirationRelativeToNow = null)
   177→        {
   178→            _inner   = inner   ?? throw new ArgumentNullException(nameof(inner));
   179→            _cache   = cache   ?? throw new ArgumentNullException(nameof(cache));
   180→            _logger  = logger  ?? throw new ArgumentNullException(nameof(logger));
   181→
   182→            _cacheOptions = new MemoryCacheEntryOptions
   183→            {
   184→                AbsoluteExpirationRelativeToNow = absoluteExpirationRelativeToNow ?? TimeSpan.FromMinutes(15),
   185→                SlidingExpiration               = TimeSpan.FromMinutes( 5)
   186→            };
   187→        }
   188→
   189→        public async Task<Post?> GetByIdAsync(Guid id, CancellationToken cancellationToken = default)
   190→        {
   191→            var cacheKey = BuildCacheKey(id);
   192→
   193→            if (_cache.TryGetValue(cacheKey, out Post cached))
   194→            {
   195→                IncrementHit();
   196→                _logger.LogDebug("Cache HIT for post {PostId}", id);
   197→                return cached;
   198→            }
   199→
   200→            IncrementMiss();
   201→            _logger.LogDebug("Cache MISS for post {PostId}", id);
   202→
   203→            var post = await _inner.GetByIdAsync(id, cancellationToken).ConfigureAwait(false);
   204→
   205→            if (post is not null)
   206→            {
   207→                _cache.Set(cacheKey, post, _cacheOptions);
   208→                UpdateSizeEstimate(post);
   209→            }
   210→
   211→            return post;
   212→        }
   213→
   214→        public async Task SaveAsync(Post post, CancellationToken cancellationToken = default)
   215→        {
   216→            await _inner.SaveAsync(post, cancellationToken).ConfigureAwait(false);
   217→
   218→            var cacheKey = BuildCacheKey(post.Id);
   219→            _cache.Set(cacheKey, post, _cacheOptions);
   220→            UpdateSizeEstimate(post);
   221→        }
   222→
   223→        public async Task DeleteAsync(Guid id, CancellationToken cancellationToken = default)
   224→        {
   225→            await _inner.DeleteAsync(id, cancellationToken).ConfigureAwait(false);
   226→            _cache.Remove(BuildCacheKey(id));
   227→        }
   228→
   229→        /* ---------------------------------------------------------- *
   230→         *                    Private helper methods                  *
   231→         * ---------------------------------------------------------- */
   232→
   233→        private static string BuildCacheKey(Guid id) => $"{CachePrefix}{id:N}";
   234→
   235→        private void UpdateSizeEstimate(Post post)
   236→        {
   237→            // VERY rough size approximation: string length ~= bytes for UTF-16
   238→            var postSizeBytes = (post.Title?.Length  ?? 0) * sizeof(char) +
   239→                                (post.Content?.Length ?? 0) * sizeof(char) + 256;
   240→
   241→            var currentSize = _cache.GetOrCreate(CacheMetricsKeys.SizeBytes, _ => 0L);
   242→            _cache.Set(CacheMetricsKeys.SizeBytes, currentSize + postSizeBytes);
   243→        }
   244→
   245→        private void IncrementHit()
   246→        {
   247→            var hits = _cache.GetOrCreate(CacheMetricsKeys.HitCounter, _ => 0L);
   248→            _cache.Set(CacheMetricsKeys.HitCounter, hits + 1);
   249→        }
   250→
   251→        private void IncrementMiss()
   252→        {
   253→            var misses = _cache.GetOrCreate(CacheMetricsKeys.MissCounter, _ => 0L);
   254→            _cache.Set(CacheMetricsKeys.MissCounter, misses + 1);
   255→        }
   256→
   257→        private static class CacheMetricsKeys
   258→        {
   259→            public const string HitCounter  = "__temposcribe_cache_hits";
   260→            public const string MissCounter = "__temposcribe_cache_misses";
   261→            public const string SizeBytes   = "__temposcribe_cache_size_bytes";
   262→        }
   263→    }
   264→
   265→    /* -------------------------------------------------------------- *
   266→     *                    Utility/extension helpers                   *
   267→     * -------------------------------------------------------------- */
   268→
   269→    internal static class ExceptionExtensions
   270→    {
   271→        /// <summary>
   272→        /// Determines whether the supplied exception is fatal enough that
   273→        /// the process should avoid catching it.
   274→        /// </summary>
   275→        public static bool IsFatal(this Exception exception) =>
   276→            exception is OutOfMemoryException or StackOverflowException;
   277→    }
   278→}
