   129→    internal sealed class EditorialAnalyticsService : IEditorialAnalyticsService
   130→    {
   131→        private const string CacheKeyTemplate = "analytics:post:{0}:from:{1:yyyyMMddHHmmss}:to:{2:yyyyMMddHHmmss}";
   132→        private readonly IAnalyticsRepository _repository;
   133→        private readonly IAnalyticsCache _cache;
   134→        private readonly ILogger<EditorialAnalyticsService> _logger;
   135→        private readonly TimeSpan _summaryTtl = TimeSpan.FromMinutes(10);
   136→
   137→        public EditorialAnalyticsService(
   138→            IAnalyticsRepository repository,
   139→            IAnalyticsCache cache,
   140→            ILogger<EditorialAnalyticsService> logger)
   141→        {
   142→            _repository = repository ?? throw new ArgumentNullException(nameof(repository));
   143→            _cache      = cache      ?? throw new ArgumentNullException(nameof(cache));
   144→            _logger     = logger     ?? throw new ArgumentNullException(nameof(logger));
