   147→        /// <inheritdoc />
   148→        public async Task RecordEventAsync(
   149→            AnalyticsEventType eventType,
   150→            Guid? postId,
   151→            Guid? userId,
   152→            string? metadataJson = null,
   153→            CancellationToken ct = default)
   154→        {
   155→            if (ct.IsCancellationRequested) return;
   156→
   157→            var evt = new AnalyticsEvent(
   158→                EventId: Guid.NewGuid(),
   159→                EventType: eventType,
   160→                PostId: postId,
   161→                UserId: userId,
   162→                OccurredAt: DateTime.UtcNow,
   163→                MetadataJson: metadataJson);
   164→
   165→            try
   166→            {
   167→                await _repository.SaveAsync(evt, ct).ConfigureAwait(false);
   168→
   169→                // Bust any summary cache for the post because underlying events changed
   170→                if (postId.HasValue)
   171→                {
   172→                    var pattern = $"analytics:post:{postId.Value}:*";
   173→                    await _cache.InvalidateAsync(pattern, ct).ConfigureAwait(false);
   174→                }
   175→
   176→                _logger.LogDebug("Analytics event {EventId} persisted.", evt.EventId);
   177→            }
   178→            catch (Exception ex) when (!ex.IsFatal())
   179→            {
   180→                _logger.LogError(ex, "Failed to record analytics event {EventId}.", evt.EventId);
   181→                throw;
   182→            }
   183→        }
   184→
   185→        /// <inheritdoc />
   186→        public Task<PostAnalyticsSummary> GetPostSummaryAsync(
   187→            Guid postId,
   188→            DateTime from,
   189→            DateTime to,
   190→            CancellationToken ct = default)
   191→        {
   192→            if (from >= to) throw new ArgumentException("`from` must be earlier than `to`.");
