   223→    /// <summary>
   224→    /// Redis-backed implementation of the analytics cache port.
   225→    /// Uses StackExchange.Redis for high-performance networking.
   226→    /// </summary>
   227→    public sealed class RedisAnalyticsCacheAdapter : IAnalyticsCache, IDisposable
   228→    {
   229→        private readonly IDatabase _db;
   230→        private readonly IConnectionMultiplexer _connection;
   231→        private readonly ILogger<RedisAnalyticsCacheAdapter> _logger;
   232→        private bool _disposed;
   233→
   234→        public RedisAnalyticsCacheAdapter(
   235→            string connectionString,
   236→            ILogger<RedisAnalyticsCacheAdapter> logger)
   237→        {
   238→            _logger = logger ?? throw new ArgumentNullException(nameof(logger));
   239→
   240→            try
   241→            {
   242→                _connection = ConnectionMultiplexer.Connect(connectionString);
   243→                _db = _connection.GetDatabase();
   244→            }
   245→            catch (Exception ex)
   246→            {
   247→                _logger.LogCritical(ex, "Unable to connect to Redis at '{ConnectionString}'.", connectionString);
   248→                throw;
   249→            }
   250→        }
   251→
   252→        /// <inheritdoc />
   253→        public async Task<T?> GetOrAddAsync<T>(
   254→            string cacheKey,
   255→            Func<Task<T>> factory,
   256→            TimeSpan ttl,
   257→            CancellationToken ct = default)
   258→        {
   259→            if (_disposed) throw new ObjectDisposedException(nameof(RedisAnalyticsCacheAdapter));
   260→            if (string.IsNullOrWhiteSpace(cacheKey)) throw new ArgumentException("Cache key cannot be null or empty.");
   261→
   262→            try
   263→            {
   264→                // Try to get from cache
   265→                var cached = await _db.StringGetAsync(cacheKey).ConfigureAwait(false);
   266→                if (cached.HasValue)
   267→                {
   268→                    return JsonSerializer.Deserialize<T>(cached!);
   269→                }
   270→
   271→                // Not found, compute via factory
   272→                var result = await factory().ConfigureAwait(false);
   273→
   274→                // Store if not canceled
   275→                if (!ct.IsCancellationRequested)
   276→                {
   277→                    var serialized = JsonSerializer.Serialize(result);
   278→                    await _db.StringSetAsync(cacheKey, serialized, ttl).ConfigureAwait(false);
   279→                }
   280→
   281→                return result;
   282→            }
   283→            catch (Exception ex) when (!ex.IsFatal())
   284→            {
   285→                _logger.LogError(ex, "Cache lookup failed for key '{CacheKey}'. Falling back to factory.", cacheKey);
   286→                return await factory().ConfigureAwait(false);
   287→            }
   288→        }
   289→
   290→        /// <inheritdoc />
   291→        public async Task InvalidateAsync(string cacheKeyPattern, CancellationToken ct = default)
   292→        {
   293→            if (_disposed) throw new ObjectDisposedException(nameof(RedisAnalyticsCacheAdapter));
   294→            if (string.IsNullOrWhiteSpace(cacheKeyPattern)) return;
   295→
   296→            // WARNING: KEYS pattern is O(N). Suitable here due to narrow scope but
   297→            // consider server-side Lua script or redis-cluster friendly approach in production.
   298→            try
   299→            {
   300→                var server = GetServer();
   301→                var keys = server.Keys(pattern: cacheKeyPattern);
   302→                foreach (var key in keys)
   303→                {
   304→                    await _db.KeyDeleteAsync(key).ConfigureAwait(false);
   305→                }
   306→            }
   307→            catch (Exception ex) when (!ex.IsFatal())
   308→            {
   309→                _logger.LogWarning(ex, "Cache invalidation failed for pattern '{Pattern}'.", cacheKeyPattern);
   310→            }
   311→        }
   312→
   313→        private IServer GetServer()
   314→        {
   315→            // Use first endpoint for simplicity. Production code might do better selection.
   316→            var endpoint = _connection.GetEndPoints().First();
   317→            return _connection.GetServer(endpoint);
   318→        }
   319→
   320→        public void Dispose()
   321→        {
