    14→    /// <summary>
    15→    ///     Orchestrates the end-to-end workflow for granting a reader access to premium content.
    16→    ///     The service is intentionally free of infrastructure technology concerns.
    17→    ///     • Reads posts and monetization rules from repositories (ports)
    18→    ///     • Charges the reader through an injected payment gateway (adapter)
    19→    ///     • Caches the purchase using an injected cache provider (adapter)
    20→    ///     • Emits domain events for downstream analytics pipelines
    21→    /// </summary>
    22→    public sealed class PaymentProcessingService : IPaymentProcessingService
    23→    {
    24→        private const string CacheKeyFormat = "premium:{0}:post:{1}";
    25→        private readonly IPostRepository _postRepository;
    26→        private readonly IPurchaseRepository _purchaseRepository;
    27→        private readonly IPaymentGateway _paymentGateway;
