    31→
    32→        public PaymentProcessingService(
    33→            IPostRepository postRepository,
    34→            IPurchaseRepository purchaseRepository,
    35→            IPaymentGateway paymentGateway,
    36→            ICacheProvider cache,
    37→            IEventBus eventBus,
    38→            ILogger<PaymentProcessingService> logger)
    39→        {
    40→            _postRepository    = postRepository    ?? throw new ArgumentNullException(nameof(postRepository));
    41→            _purchaseRepository = purchaseRepository ?? throw new ArgumentNullException(nameof(purchaseRepository));
    42→            _paymentGateway    = paymentGateway    ?? throw new ArgumentNullException(nameof(paymentGateway));
    43→            _cache             = cache             ?? throw new ArgumentNullException(nameof(cache));
    44→            _eventBus          = eventBus          ?? throw new ArgumentNullException(nameof(eventBus));
    45→            _logger            = logger            ?? throw new ArgumentNullException(nameof(logger));
    46→        }
