    48→        /// <inheritdoc />
    49→        public async Task<PostContent> AccessPremiumContentAsync(
    50→            UserId readerId,
    51→            PostId postId,
    52→            PaymentMethodToken paymentMethod,
    53→            CancellationToken cancellationToken = default)
    54→        {
    55→            if (readerId == default)   throw new ArgumentException(nameof(readerId));
    56→            if (postId   == default)   throw new ArgumentException(nameof(postId));
    57→            if (paymentMethod == default) throw new ArgumentException(nameof(paymentMethod));
    58→
    59→            var cacheKey = string.Format(CacheKeyFormat, readerId, postId);
    60→
    61→            // 1. Fast-path: User already purchased this post
    62→            var cachedContent = await _cache.GetAsync<PostContent>(cacheKey, cancellationToken);
    63→            if (cachedContent is not null)
    64→            {
    65→                _logger.LogDebug("Cache hit for premium content. reader={ReaderId}, post={PostId}", readerId, postId);
    66→                return cachedContent;
    67→            }
    68→
    69→            // 2. Retrieve & validate post
    70→            var post = await _postRepository.GetByIdAsync(postId, cancellationToken)
    71→                       ?? throw new NotFoundException($"Post with id '{postId}' was not found.");
    72→
    73→            if (!post.IsPremium)
    74→            {
    75→                // Non-premium content: simply return
    76→                _logger.LogDebug("Post {PostId} is public, bypassing payment gateway.", postId);
    77→                return post.Content;
    78→            }
    79→
    80→            // 3. Determine price via monetization rules
    81→            var price = post.MonetizationRule.EvaluatePrice(readerId);
    82→            _logger.LogInformation("Calculated price {Price} for reader {ReaderId} on post {PostId}.", price, readerId, postId);
    83→
    84→            // 4. Execute payment
    85→            PaymentReceipt receipt;
    86→            try
    87→            {
    88→                receipt = await _paymentGateway.ChargeAsync(
    89→                    readerId: readerId,
    90→                    amount: price,
    91→                    paymentMethod: paymentMethod,
    92→                    metadata: new { PostId = postId.Value },
    93→                    cancellationToken: cancellationToken);
    94→            }
    95→            catch (PaymentDeclinedException ex)
    96→            {
    97→                _logger.LogWarning(ex, "Payment declined for reader {ReaderId}, post {PostId}.", readerId, postId);
    98→                throw;  // Bubble up for controller/UI to surface a friendly message
    99→            }
   100→
   101→            // 5. Persist purchase record (for audit & refunds)
   102→            var purchase = Purchase.CreateSuccessful(
   103→                readerId,
   104→                postId,
   105→                receivedAtUtc: receipt.TimestampUtc,
   106→                grossAmount: price,
   107→                paymentGatewayTransactionId: receipt.TransactionId);
   108→
   109→            await _purchaseRepository.AddAsync(purchase, cancellationToken);
   110→
   111→            // 6. Cache purchased content to avoid re-billing
   112→            await _cache.SetAsync(cacheKey, post.Content,
   113→                                  options: CacheEntryOptions.AbsoluteExpiration(TimeSpan.FromDays(30)),
   114→                                  cancellationToken: cancellationToken);
   115→
   116→            // 7. Emit domain event for analytics pipeline
   117→            var domainEvent = new PremiumContentAccessedDomainEvent(
   118→                readerId,
   119→                postId,
   120→                price,
   121→                receipt.TransactionId,
   122→                occurredOnUtc: DateTime.UtcNow);
   123→
   124→            await _eventBus.PublishAsync(domainEvent, cancellationToken);
   125→
   126→            _logger.LogInformation("Reader {ReaderId} completed purchase for post {PostId}.", readerId, postId);
   127→
   128→            return post.Content;
   129→        }
   130→    }
