    97→    /// <summary>
    98→    /// Production-ready adapter that stores draft preview HTML in Redis with an
    99→    /// automatic local fallback in case of connectivity issues. The adapter
   100→    /// attempts to be lock-safe by leveraging SETNX semantics to prevent lost
   101→    /// updates.
   102→    /// </summary>
   103→    public sealed class RedisContentPreviewCacheAdapter : IContentPreviewCache, IDisposable
   104→    {
   105→        private readonly RedisContentPreviewCacheOptions _options;
   106→        private readonly ILogger<RedisContentPreviewCacheAdapter> _logger;
   107→        private readonly IMemoryCache _fallbackCache;
   108→        private readonly ConnectionMultiplexer _connection;
   109→        private readonly IDatabase _database;
   110→
   111→        private static readonly string LockSuffix = ":lock";
   112→        private static readonly string PreviewSuffix = ":preview";
   113→
   114→        public RedisContentPreviewCacheAdapter(
   115→            IOptions<RedisContentPreviewCacheOptions> options,
   116→            ILogger<RedisContentPreviewCacheAdapter> logger,
   117→            IMemoryCache? memoryCache = null)
   118→        {
   119→            _options = options?.Value ?? throw new ArgumentNullException(nameof(options));
   120→            _logger = logger ?? throw new ArgumentNullException(nameof(logger));
   121→
   122→            // Initialize a lightweight in-memory fallback cache.
   123→            _fallbackCache = memoryCache ?? new MemoryCache(new MemoryCacheOptions
   124→            {
   125→                SizeLimit = 128
   126→            });
   127→
   128→            try
   129→            {
   130→                var configuration = ConfigurationOptions.Parse(_options.Endpoints);
   131→                configuration.AbortOnConnectFail = false;
   132→                _connection = ConnectionMultiplexer.Connect(configuration);
   133→                _database = _connection.GetDatabase(_options.DatabaseId);
   134→            }
   135→            catch (Exception ex)
   136→            {
   137→                _logger.LogError(ex,
   138→                    "Unable to establish initial Redis connection. System will rely " +
   139→                    "on in-process fallback cache until connectivity is restored.");
   140→                // Connection mut be set but may not be connected yet.
   141→                _connection = ConnectionMultiplexer.Connect("localhost"); // Dummy for dispose pattern
   142→                _database = _connection.GetDatabase(_options.DatabaseId);
   143→            }
   144→        }
   145→
   146→        public async Task<string?> GetDraftPreviewAsync(Guid postId, CancellationToken ct = default)
   147→        {
   148→            ct.ThrowIfCancellationRequested();
   149→
   150→            var key = BuildCacheKey(postId);
   151→            try
   152→            {
   153→                string? cached = await _database.StringGetAsync(key);
   154→                if (cached != null)
   155→                {
   156→                    _logger.LogDebug("Preview retrieved for PostId={PostId} (Redis)", postId);
   157→                    _fallbackCache.Set(key, cached,
   158→                        TimeSpan.FromMinutes(_options.LocalFallbackExpirationMinutes));
   159→                    return cached;
   160→                }
   161→
   162→                if (_fallbackCache.TryGetValue<string>(key, out var fallback))
   163→                {
   164→                    _logger.LogDebug("Preview retrieved for PostId={PostId} (MemoryFallback)", postId);
   165→                    return fallback;
   166→                }
   167→
   168→                return null;
   169→            }
   170→            catch (Exception ex)
   171→            {
   172→                _logger.LogWarning(ex, "Redis unavailable. Falling back to in-memory cache.");
   173→                if (_fallbackCache.TryGetValue<string>(key, out var fallback))
   174→                    return fallback;
   175→
   176→                throw new ContentPreviewCacheException(
   177→                    "Failed to retrieve preview from Redis and fallback cache.", ex);
   178→            }
   179→        }
