   181→        public async Task SaveDraftPreviewAsync(Guid postId, string html, CancellationToken ct = default)
   182→        {
   183→            if (html is null) throw new ArgumentNullException(nameof(html));
   184→            ct.ThrowIfCancellationRequested();
   185→
   186→            var key = BuildCacheKey(postId);
   187→            var lockKey = key + LockSuffix;
   188→            var lockValue = Environment.MachineName + ":" + Guid.NewGuid().ToString("N");
   189→
   190→            try
   191→            {
   192→                // Basic distributed lock using SET NX PX pattern
   193→                bool acquired = await _database.StringSetAsync(
   194→                    lockKey, lockValue,
   195→                    TimeSpan.FromMilliseconds(_options.LockWaitTimeoutMilliseconds),
   196→                    When.NotExists);
   197→
   198→                if (!acquired)
   199→                {
   200→                    _logger.LogDebug("Lock acquisition timed out for PostId={PostId}", postId);
   201→                    return; // Another write in progress; skip to avoid thrashing
   202→                }
   203→
   204→                await _database.StringSetAsync(
   205→                    key,
   206→                    html,
   207→                    TimeSpan.FromMinutes(_options.PreviewExpirationMinutes));
   208→
   209→                _logger.LogDebug("Preview saved for PostId={PostId}", postId);
   210→
   211→                _fallbackCache.Set(key, html,
   212→                    TimeSpan.FromMinutes(_options.LocalFallbackExpirationMinutes));
   213→            }
   214→            catch (Exception ex)
   215→            {
   216→                _logger.LogWarning(ex, "Unable to save preview to Redis. Storing to fallback cache.");
   217→                _fallbackCache.Set(key, html,
   218→                    TimeSpan.FromMinutes(_options.LocalFallbackExpirationMinutes));
   219→                throw new ContentPreviewCacheException("Failed to save preview to Redis.", ex);
   220→            }
   221→            finally
   222→            {
   223→                // Best-effort lock release
   224→                try
   225→                {
   226→                    var currentValue = await _database.StringGetAsync(lockKey);
   227→                    if (currentValue == lockValue)
   228→                        await _database.KeyDeleteAsync(lockKey);
   229→                }
   230→                catch (Exception ex)
   231→                {
   232→                    _logger.LogDebug(ex, "Error while releasing Redis lock for PostId={PostId}", postId);
   233→                }
   234→            }
   235→        }
   236→
   237→        public async Task InvalidatePreviewAsync(Guid postId, CancellationToken ct = default)
   238→        {
   239→            ct.ThrowIfCancellationRequested();
   240→
   241→            var key = BuildCacheKey(postId);
   242→            try
   243→            {
   244→                await _database.KeyDeleteAsync(key);
   245→                _fallbackCache.Remove(key);
   246→                _logger.LogDebug("Preview invalidated for PostId={PostId}", postId);
   247→            }
   248→            catch (Exception ex)
   249→            {
   250→                _logger.LogWarning(ex, "Unable to invalidate preview for PostId={PostId} in Redis.", postId);
   251→                _fallbackCache.Remove(key); // Even if Redis fails, ensure local is cleared
   252→                throw new ContentPreviewCacheException("Failed to invalidate preview.", ex);
   253→            }
   254→        }
   255→
   256→        private string BuildCacheKey(Guid postId)
   257→            => $"{_options.KeyPrefix}{PreviewSuffix}|{postId.ToString("N", CultureInfo.InvariantCulture)}";
