   281→    /// <summary>
   282→    /// Lightweight diffing implementation designed for HTML previews. The goal
   283→    /// is not a pixel-perfect diff, but a performant, readable markup (<ins>,
   284→    /// <del>) that editors can consume immediately in the live preview panel.
   285→    /// This implementation is intentionally simple to keep the dependency
   286→    /// footprint small; however, it can be transparently swapped for a more
   287→    /// advanced algorithm via the IPreviewDiffService port.
   288→    /// </summary>
   289→    public sealed class HtmlPreviewDiffService : IPreviewDiffService
   290→    {
   291→        private readonly ILogger<HtmlPreviewDiffService> _logger;
   292→
   293→        public HtmlPreviewDiffService(ILogger<HtmlPreviewDiffService> logger)
   294→        {
   295→            _logger = logger ?? throw new ArgumentNullException(nameof(logger));
   296→        }
   297→
   298→        public string ComputeDiff(string oldHtml, string newHtml)
   299→        {
   300→            if (oldHtml == null) throw new ArgumentNullException(nameof(oldHtml));
   301→            if (newHtml == null) throw new ArgumentNullException(nameof(newHtml));
   302→
   303→            if (oldHtml.Equals(newHtml, StringComparison.Ordinal))
   304→                return newHtml; // No changes; return as-is to save cycles
   305→
   306→            try
   307→            {
   308→                var sb = new StringBuilder(EstimateCapacity(oldHtml, newHtml));
   309→
   310→                int i = 0, j = 0;
   311→                while (i < oldHtml.Length && j < newHtml.Length)
   312→                {
   313→                    if (oldHtml[i] == newHtml[j])
   314→                    {
   315→                        sb.Append(oldHtml[i]);
   316→                        i++; j++;
   317→                    }
   318→                    else
   319→                    {
   320→                        // Naive diff: mark deletions then insertions
   321→                        int startOld = i;
   322→                        int startNew = j;
   323→                        while (i < oldHtml.Length && (j >= newHtml.Length || oldHtml[i] != newHtml[j]))
   324→                            i++;
   325→
   326→                        while (j < newHtml.Length && (i >= oldHtml.Length || oldHtml[i] != newHtml[j]))
   327→                            j++;
   328→
   329→                        var deleted = oldHtml.Substring(startOld, i - startOld);
   330→                        var inserted = newHtml.Substring(startNew, j - startNew);
   331→
   332→                        if (deleted.Length > 0)
   333→                            sb.Append($"<del>{System.Net.WebUtility.HtmlEncode(deleted)}</del>");
   334→                        if (inserted.Length > 0)
   335→                            sb.Append($"<ins>{System.Net.WebUtility.HtmlEncode(inserted)}</ins>");
   336→                    }
   337→                }
   338→
   339→                if (i < oldHtml.Length)
   340→                    sb.Append($"<del>{System.Net.WebUtility.HtmlEncode(oldHtml.Substring(i))}</del>");
   341→                if (j < newHtml.Length)
   342→                    sb.Append($"<ins>{System.Net.WebUtility.HtmlEncode(newHtml.Substring(j))}</ins>");
   343→
   344→                return sb.ToString();
   345→            }
   346→            catch (Exception ex)
   347→            {
   348→                _logger.LogError(ex, "Diff generation failed. Falling back to newHtml.");
   349→                return newHtml;
   350→            }
   351→        }
   352→
   353→        private static int EstimateCapacity(string s1, string s2)
   354→            => (s1.Length + s2.Length) * 2; // Rough estimate for StringBuilder size
   355→    }
