    25→namespace TempoScribePro.Adapters.Scheduling
    26→{
    27→    #region Domain Contracts (Ports)
    28→
    29→    /// <summary>
    30→    /// Value object wrapper for a post identifier.
    31→    /// </summary>
    32→    public readonly record struct PostId(Guid Value)
    33→    {
    34→        public override string ToString() => Value.ToString("N", CultureInfo.InvariantCulture);
    35→
    36→        public static PostId New() => new PostId(Guid.NewGuid());
    37→    }
    38→
    39→    /// <summary>
    40→    /// Port that the domain layer uses to schedule or cancel future publications.
    41→    /// </summary>
    42→    public interface IPublishScheduler
    43→    {
    44→        /// <summary>
    45→        /// Schedules a post to be published at a specific moment in UTC.
    46→        /// If a schedule already exists it is replaced.
    47→        /// </summary>
    48→        Task SchedulePostAsync(PostId postId, DateTime utcPublishAt, CancellationToken ct = default);
    49→
    50→        /// <summary>
    51→        /// Cancels a previously scheduled publication (if any).
    52→        /// </summary>
    53→        Task CancelScheduledPostAsync(PostId postId, CancellationToken ct = default);
    54→    }
    55→
    56→    #endregion
    57→
    58→    #region Quartz Adapter
    59→
    60→    /// <summary>
    61→    /// Quartz‐powered implementation of <see cref="IPublishScheduler"/>.
    62→    /// </summary>
    63→    public sealed class QuartzPublishScheduler : IPublishScheduler
    64→    {
    65→        private readonly IScheduler _scheduler;
    66→        private readonly ILogger<QuartzPublishScheduler> _logger;
    67→
    68→        public QuartzPublishScheduler(IScheduler scheduler, ILogger<QuartzPublishScheduler>? logger = null)
    69→        {
    70→            _scheduler = scheduler ?? throw new ArgumentNullException(nameof(scheduler));
    71→            _logger    = logger     ?? Microsoft.Extensions.Logging.Abstractions.NullLogger<QuartzPublishScheduler>.Instance;
    72→        }
    73→
    74→        public async Task SchedulePostAsync(PostId postId, DateTime utcPublishAt, CancellationToken ct = default)
    75→        {
    76→            if (utcPublishAt.Kind != DateTimeKind.Utc)
    77→                throw new ArgumentException("utcPublishAt must be expressed in UTC.", nameof(utcPublishAt));
    78→
    79→            var job     = CreateJobDetail(postId);
    80→            var trigger = CreateTrigger(postId, utcPublishAt);
    81→
    82→            await _scheduler.ScheduleJob(job, new[] { trigger }, true, ct);
    83→
    84→            _logger.LogInformation(
    85→                "Scheduled post {PostId} for publication at {PublishAt:o} (UTC).", 
    86→                postId, utcPublishAt);
    87→        }
    88→
    89→        public async Task CancelScheduledPostAsync(PostId postId, CancellationToken ct = default)
    90→        {
    91→            var jobKey   = JobKeyFor(postId);
    92→            var jobGroup = JobGroupFor(postId);
    93→
    94→            // Only delete job if matching group exists to avoid wiping out unrelated jobs.
    95→            if (await _scheduler.CheckExists(jobKey, ct))
    96→            {
    97→                await _scheduler.DeleteJob(jobKey, ct);
    98→                _logger.LogInformation("Cancelled scheduled publication for post {PostId}.", postId);
    99→            }
   100→            else
   101→            {
   102→                _logger.LogDebug(
   103→                    "No scheduled publication found to cancel for post {PostId}.", postId);
   104→            }
   105→
   106→            // Clean up orphaned triggers (defensive).
   107→            var matcher = GroupMatcher<TriggerKey>.GroupEquals(jobGroup);
   108→            foreach (var triggerKey in await _scheduler.GetTriggerKeys(matcher, ct))
   109→            {
   110→                await _scheduler.UnscheduleJob(triggerKey, ct);
   111→            }
   112→        }
   113→
   114→        #region Helpers
   115→
   116→        private static IJobDetail CreateJobDetail(PostId postId)
   117→        {
   118→            return JobBuilder.Create<PublishJob>()
   119→                             .WithIdentity(JobKeyFor(postId))
   120→                             .UsingJobData(PublishJob.JobDataPostIdKey, postId.ToString())
   121→                             .StoreDurably(false)
   122→                             .RequestRecovery(true)
   123→                             .Build();
   124→        }
   125→
   126→        private static ITrigger CreateTrigger(PostId postId, DateTime utcPublishAt)
   127→        {
   128→            return TriggerBuilder.Create()
   129→                                 .WithIdentity(TriggerKeyFor(postId))
   130→                                 .StartAt(utcPublishAt)
   131→                                 .WithSimpleSchedule(x => x.WithMisfireHandlingInstructionFireNow())
   132→                                 .ForJob(JobKeyFor(postId))
   133→                                 .Build();
   134→        }
   135→
   136→        private static string JobGroupFor(PostId postId)     => $"post-{postId}";
   137→        private static JobKey JobKeyFor(PostId postId)       => new($"publish-{postId}", JobGroupFor(postId));
   138→        private static TriggerKey TriggerKeyFor(PostId postId) => new($"trigger-{postId}", JobGroupFor(postId));
   139→
   140→        #endregion
   141→    }
