   143→    /// <summary>
   144→    /// Quartz job responsible for delegating the actual publish operation.
   145→    /// It pushes an integration event onto the internal event bus, or invokes
   146→    /// an application service, depending on the configured delegate.
   147→    /// </summary>
   148→    public sealed class PublishJob : IJob
   149→    {
   150→        public const string JobDataPostIdKey = "PostId";
   151→
   152→        private readonly IPublishCommand _publishCommand;
   153→        private readonly ILogger<PublishJob> _logger;
   154→
   155→        public PublishJob(IPublishCommand publishCommand, ILogger<PublishJob>? logger = null)
   156→        {
   157→            _publishCommand = publishCommand 
   158→                              ?? throw new ArgumentNullException(nameof(publishCommand));
   159→            _logger         = logger 
   160→                              ?? Microsoft.Extensions.Logging.Abstractions.NullLogger<PublishJob>.Instance;
   161→        }
   162→
   163→        public async Task Execute(IJobExecutionContext context)
   164→        {
   165→            var postIdRaw = context.MergedJobDataMap.GetString(JobDataPostIdKey);
   166→
   167→            if (!Guid.TryParse(postIdRaw, out var guid))
   168→            {
   169→                _logger.LogError(
   170→                    "PublishJob aborted – invalid PostId in JobData: {PostIdRaw}", postIdRaw);
   171→                return;
   172→            }
   173→
   174→            var postId = new PostId(guid);
   175→
   176→            _logger.LogInformation(
   177→                "Executing scheduled publication for post {PostId} at {FireTimeUtc:o}.",
   178→                postId, context.FireTimeUtc?.UtcDateTime);
   179→
   180→            try
   181→            {
   182→                await _publishCommand.PublishAsync(postId, context.CancellationToken);
   183→            }
   184→            catch (Exception ex)
   185→            {
   186→                // Rethrow to let Quartz trigger retry policies if configured.
   187→                _logger.LogError(ex, "Publishing failed for post {PostId}. Scheduling retry.", postId);
   188→                throw;
   189→            }
   190→        }
   191→    }
   192→
   193→    #endregion
   194→
   195→    #region Fallback/In-Memory Adapter
   196→
   197→    /// <summary>
   198→    /// Minimal in‐memory scheduling implementation intended for unit tests or
   199→    /// single‐process execution environments where Quartz is unavailable.
   200→    /// </summary>
   201→    public sealed class InMemoryPublishScheduler : IPublishScheduler, IDisposable
   202→    {
   203→        private readonly ConcurrentDictionary<PostId, Timer> _timers  = new();
   204→        private readonly IPublishCommand                     _command;
   205→        private readonly ILogger<InMemoryPublishScheduler>    _logger;
   206→
   207→        public InMemoryPublishScheduler(
   208→            IPublishCommand command,
   209→            ILogger<InMemoryPublishScheduler>? logger = null)
   210→        {
   211→            _command = command 
   212→                       ?? throw new ArgumentNullException(nameof(command));
   213→            _logger  = logger 
   214→                       ?? Microsoft.Extensions.Logging.Abstractions.NullLogger<InMemoryPublishScheduler>.Instance;
   215→        }
   216→
   217→        public Task SchedulePostAsync(PostId postId, DateTime utcPublishAt, CancellationToken ct = default)
   218→        {
   219→            if (utcPublishAt.Kind != DateTimeKind.Utc)
   220→                throw new ArgumentException("utcPublishAt must be expressed in UTC.", nameof(utcPublishAt));
   221→
   222→            // Dispose previous timer if we are rescheduling.
   223→            if (_timers.TryRemove(postId, out var existing))
   224→                existing.Dispose();
   225→
   226→            var delay = utcPublishAt - DateTime.UtcNow;
   227→            if (delay < TimeSpan.Zero)
   228→                delay = TimeSpan.Zero; // Fire ASAP if in the past.
   229→
   230→            var timer = new Timer(async _ => await ExecutePublishAsync(postId),
   231→                                  null,
   232→                                  delay,
   233→                                  Timeout.InfiniteTimeSpan);
   234→
   235→            _timers[postId] = timer;
   236→            _logger.LogInformation("In-memory scheduled post {PostId} at {PublishAt:o}.", postId, utcPublishAt);
   237→
   238→            return Task.CompletedTask;
   239→        }
   240→
   241→        public Task CancelScheduledPostAsync(PostId postId, CancellationToken ct = default)
   242→        {
   243→            if (_timers.TryRemove(postId, out var timer))
   244→            {
   245→                timer.Dispose();
   246→                _logger.LogInformation("Cancelled in-memory scheduled post {PostId}.", postId);
   247→            }
   248→
   249→            return Task.CompletedTask;
   250→        }
   251→
   252→        private async Task ExecutePublishAsync(PostId postId)
   253→        {
   254→            try
   255→            {
   256→                await _command.PublishAsync(postId);
   257→                _logger.LogInformation("In-memory executed publication for post {PostId}.", postId);
   258→            }
   259→            catch (Exception ex)
   260→            {
   261→                _logger.LogError(ex, "In-memory publication failed for post {PostId}.", postId);
   262→            }
   263→            finally
   264→            {
   265→                // Clean up timer to prevent memory leaks.
   266→                CancelScheduledPostAsync(postId).GetAwaiter().GetResult();
   267→            }
   268→        }
   269→
   270→        public void Dispose()
   271→        {
   272→            foreach (var kvp in _timers)
   273→                kvp.Value.Dispose();
   274→            _timers.Clear();
   275→        }
   276→    }
   277→
   278→    #endregion
   279→
   280→    #region Internal Commands
   281→
   282→    /// <summary>
   283→    /// Application service (or domain use‐case) responsible for publishing a post
   284→    /// immediately.  Abstraction allows the scheduler to stay isolated.
   285→    /// </summary>
   286→    public interface IPublishCommand
   287→    {
   288→        /// <summary>
   289→        /// Executes an immediate publish operation, regardless of current status.
   290→        /// </summary>
   291→        Task PublishAsync(PostId postId, CancellationToken ct = default);
   292→    }
   293→
   294→    #endregion
   295→}
