    40→
    41→/// <summary>
    42→///     Orchestrates scheduled publishing of blog posts.
    43→/// </summary>
    44→public sealed class ScheduledPublishingService : IScheduledPublishingService
    45→{
    46→    private const string DistributedLockKey = "tempo:scheduled-publishing:lock";
    47→    private static readonly TimeSpan LockTtl = TimeSpan.FromMinutes(2);
    48→
    49→    private readonly IPostRepository            _postRepository;
    50→    private readonly IUnitOfWork                _unitOfWork;
    51→    private readonly IDateTimeProvider          _dateTimeProvider;
    52→    private readonly IEventDispatcher           _eventDispatcher;
    53→    private readonly IContentCache              _contentCache;
    54→    private readonly IDistributedLockProvider   _lockProvider;
    55→    private readonly ILogger<ScheduledPublishingService> _logger;
    56→
    57→    /// <summary>
    58→    ///     Ctor. All dependencies are injected by the IoC container.
    59→    /// </summary>
    60→    public ScheduledPublishingService(
    61→        IPostRepository                         postRepository,
    62→        IUnitOfWork                             unitOfWork,
    63→        IDateTimeProvider                       dateTimeProvider,
    64→        IEventDispatcher                        eventDispatcher,
    65→        IContentCache                           contentCache,
    66→        IDistributedLockProvider                lockProvider,
    67→        ILogger<ScheduledPublishingService>     logger)
    68→    {
    69→        _postRepository   = postRepository   ?? throw new ArgumentNullException(nameof(postRepository));
    70→        _unitOfWork       = unitOfWork       ?? throw new ArgumentNullException(nameof(unitOfWork));
    71→        _dateTimeProvider = dateTimeProvider ?? throw new ArgumentNullException(nameof(dateTimeProvider));
    72→        _eventDispatcher  = eventDispatcher  ?? throw new ArgumentNullException(nameof(eventDispatcher));
    73→        _contentCache     = contentCache     ?? throw new ArgumentNullException(nameof(contentCache));
    74→        _lockProvider     = lockProvider     ?? throw new ArgumentNullException(nameof(lockProvider));
    75→        _logger           = logger           ?? throw new ArgumentNullException(nameof(logger));
    76→    }
    77→
    78→    /// <inheritdoc />
    79→    public async Task<int> PublishDueContentAsync(CancellationToken cancellationToken = default)
    80→    {
    81→        // Attempt to acquire a short-lived distributed lock to avoid duplicate work in scaled setups.
    82→        await using var distLock = await _lockProvider.TryAcquireAsync(
    83→                                        DistributedLockKey,
    84→                                        LockTtl,
    85→                                        cancellationToken);
    86→
    87→        if (!distLock.IsAcquired)
    88→        {
    89→            _logger.LogInformation(
    90→                "ScheduledPublishingService skipped execution because another node holds the lock.");
    91→            return 0;
    92→        }
    93→
    94→        var now = _dateTimeProvider.UtcNow;
    95→        IReadOnlyCollection<Post> duePosts = await _postRepository
    96→            .GetDueScheduledPostsAsync(now, cancellationToken);
    97→
    98→        if (duePosts.Count == 0)
    99→        {
   100→            _logger.LogDebug("No posts were due for publishing at {Timestamp}", now);
   101→            return 0;
   102→        }
   103→
   104→        _logger.LogInformation("Found {PostCount} post(s) due for publishing.", duePosts.Count);
   105→
   106→        var publishedCount = 0;
   107→
   108→        foreach (var post in duePosts)
   109→        {
   110→            cancellationToken.ThrowIfCancellationRequested();
   111→
   112→            try
   113→            {
   114→                if (!post.CanTransitionToPublished())
   115→                {
   116→                    _logger.LogWarning(
   117→                        "Post {PostId} is marked as scheduled but cannot transition to 'Published'. Skipping.",
   118→                        post.Id);
   119→                    continue;
   120→                }
   121→
   122→                post.Publish(now);
   123→
   124→                publishedCount++;
   125→
   126→                // Persist the domain-state transition.
   127→                await _postRepository.UpdateAsync(post, cancellationToken);
   128→
   129→                // Dispatch domain events (e.g., PostPublishedEvent).
   130→                await _eventDispatcher.DispatchAsync(post.DomainEvents, cancellationToken);
   131→
   132→                // Bust cache entries eagerly to ensure readers see fresh content.
   133→                _contentCache.RemovePost(post.Id);
   134→            }
   135→            catch (Exception ex)
   136→            {
   137→                _logger.LogError(
   138→                    ex,
   139→                    "Failed to publish scheduled post {PostId}. Error: {Message}",
   140→                    post.Id,
   141→                    ex.Message);
   142→                // Continue processing remaining posts without bubbling up.
   143→            }
   144→        }
   145→
   146→        // Commit once for all processed posts to minimize transaction overhead.
   147→        try
   148→        {
   149→            await _unitOfWork.CommitAsync(cancellationToken);
   150→        }
   151→        catch (Exception ex)
   152→        {
   153→            _logger.LogCritical(
   154→                ex,
   155→                "UnitOfWork commit failed after publishing {Count} post(s). Rolling back.",
   156→                publishedCount);
   157→
   158→            await _unitOfWork.RollbackAsync(cancellationToken);
   159→            throw; // Let higher-level handlers decide what to do.
   160→        }
   161→
   162→        _logger.LogInformation("ScheduledPublishingService published {Count} post(s).", publishedCount);
   163→
   164→        return publishedCount;
   165→    }
   166→}
   167→
   168→/// <summary>
   169→///     Service-layer abstraction for scheduled publishing so that
   170→///     orchestrators (e.g., cron jobs, background workers) can trigger it
   171→///     without knowing implementation details.
   172→/// </summary>
   173→public interface IScheduledPublishingService
   174→{
   175→    /// <summary>
   176→    ///     Publishes all posts whose <c>PublishAt</c> date is due.
   177→    /// </summary>
   178→    /// <param name="cancellationToken">Optional cancellation token.</param>
   179→    /// <returns>Number of posts successfully published.</returns>
   180→    Task<int> PublishDueContentAsync(CancellationToken cancellationToken = default);
   181→}
