   232→                _logger.LogDebug("Analytics report cached under key {CacheKey}", cacheKey);
   233→            }
   234→            catch (Exception ex) when (IsTransient(ex))
   235→            {
   236→                _logger.LogWarning(ex, "Failed to store analytics report in cache.");
   237→            }
   238→        }
   239→
   240→        private async Task<EditorialAnalyticsReport> BuildInternalAsync(
   241→            DateTime fromUtc,
   242→            DateTime toUtc,
   243→            AnalyticsGranularity granularity,
   244→            CancellationToken ct)
   245→        {
   246→            IReadOnlyList<PostAnalyticsDto> posts =
   247→                await _repository.GetPostsAsync(fromUtc, toUtc, ct);
   248→
   249→            _logger.LogDebug("Fetched {Count} posts from analytics repository", posts.Count);
   250→
   251→            // Bucket posts by chosen granularity.
   252→            var grouped = posts
   253→                .GroupBy(p => GetBucketKey(p.PublishedAtUtc, granularity))
   254→                .OrderBy(g => g.Key);
   255→
   256→            List<TimeSlice> slices = new();
   257→
   258→            foreach (IGrouping<DateTime, PostAnalyticsDto> bucket in grouped)
   259→            {
   260→                int postsPublished = bucket.Count();
   261→                int words = bucket.Sum(p => p.WordCount);
   262→                double avgReadTime = bucket.Any() ? bucket.Average(p => p.EstimatedReadTimeSeconds) : 0.0;
   263→
   264→                // Flatten tags for popularity metric.
   265→                var topTags = bucket
   266→                    .SelectMany(p => p.Tags)
   267→                    .GroupBy(t => t.ToLowerInvariant())
   268→                    .Select(g => new TagMetric(g.Key, g.Count()))
   269→                    .OrderByDescending(t => t.PostCount)
   270→                    .ThenBy(t => t.Tag)
   271→                    .Take(5)
   272→                    .ToList();
   273→
   274→                slices.Add(new TimeSlice(
   275→                    PeriodStartUtc: bucket.Key,
   276→                    PostsPublished: postsPublished,
   277→                    WordsAuthored: words,
   278→                    AvgReadTimeSeconds: Math.Round(avgReadTime, 2),
   279→                    TopTags: topTags));
   280→            }
