   282→            return new EditorialAnalyticsReport(
   283→                Slices: slices,
   284→                GeneratedBy: Environment.MachineName,
   285→                GeneratedAtUtc: DateTime.UtcNow);
   286→        }
   287→
   288→        private static DateTime GetBucketKey(DateTime timestampUtc, AnalyticsGranularity granularity) =>
