    25→
    26→/// <summary>
    27→/// Exposes functionality for promoting scheduled posts to a published state when the
    28→/// configured <see cref="IPost.ScheduledAt"/> timestamp is in the past.
    29→/// </summary>
    30→public interface IScheduledPublishingService
    31→{
    32→    /// <summary>
    33→    /// Processes every post that is currently <see cref="PostStatus.Scheduled"/> and
    34→    /// whose <see cref="IPost.ScheduledAt"/> has elapsed.
    35→    /// </summary>
    36→    /// <param name="cancellationToken">Token that cancels the ongoing operation.</param>
    37→    /// <returns>A report that summarizes the promotion run.</returns>
    38→    Task<PublishingReport> PromoteDueScheduledPostsAsync(CancellationToken cancellationToken = default);
