    40→
    41→/// <summary>
    42→/// Represents the outcome of <see cref="IScheduledPublishingService"/> execution.
    43→/// </summary>
    44→public sealed record PublishingReport(
    45→    int TotalExamined,
    46→    int SuccessfullyPublished,
    47→    int SkippedByRule,
    48→    int Failed,
    49→    IReadOnlyCollection<PublishingFailure> Failures)
    50→{
    51→    public static PublishingReport Empty =>
    52→        new(0, 0, 0, 0, Array.Empty<PublishingFailure>());
    53→}
    54→
    55→/// <summary>
    56→/// Contains information about a specific post that failed to publish.
    57→/// </summary>
    58→public sealed record PublishingFailure(PostId PostId, string Reason, Exception? Exception);
    59→
    60→/// <inheritdoc />
    61→internal sealed class ScheduledPublishingService : IScheduledPublishingService
    62→{
    63→    private readonly IPostRepository _postRepository;
    64→    private readonly IUnitOfWork _unitOfWork;
    65→    private readonly IClock _clock;
    66→    private readonly IMonetizationRuleEvaluator _monetizationRuleEvaluator;
    67→    private readonly IDomainEventDispatcher _eventDispatcher;
    68→    private readonly ILogger<ScheduledPublishingService> _logger;
    69→
    70→    public ScheduledPublishingService(
    71→        IPostRepository postRepository,
    72→        IUnitOfWork unitOfWork,
    73→        IClock clock,
    74→        IMonetizationRuleEvaluator monetizationRuleEvaluator,
    75→        IDomainEventDispatcher eventDispatcher,
    76→        ILogger<ScheduledPublishingService> logger)
    77→    {
    78→        _postRepository           = postRepository ?? throw new ArgumentNullException(nameof(postRepository));
    79→        _unitOfWork               = unitOfWork    ?? throw new ArgumentNullException(nameof(unitOfWork));
    80→        _clock                    = clock         ?? throw new ArgumentNullException(nameof(clock));
    81→        _monetizationRuleEvaluator= monetizationRuleEvaluator ?? throw new ArgumentNullException(nameof(monetizationRuleEvaluator));
    82→        _eventDispatcher          = eventDispatcher ?? throw new ArgumentNullException(nameof(eventDispatcher));
    83→        _logger                   = logger        ?? throw new ArgumentNullException(nameof(logger));
    84→    }
    85→
    86→    /// <inheritdoc />
    87→    public async Task<PublishingReport> PromoteDueScheduledPostsAsync(CancellationToken cancellationToken = default)
    88→    {
    89→        _logger.LogInformation("Scheduled publishing run started at {Instant}.", _clock.UtcNow);
    90→
    91→        IReadOnlyList<IPost> duePosts =
    92→            await _postRepository
    93→                .FindScheduledDueAsync(_clock.UtcNow, cancellationToken)
    94→                .ConfigureAwait(false);
    95→
    96→        if (duePosts.Count == 0)
    97→        {
    98→            _logger.LogInformation("No due scheduled posts found.");
    99→            return PublishingReport.Empty;
   100→        }
   101→
   102→        _logger.LogInformation("{Count} post(s) due for publishing.", duePosts.Count);
   103→
   104→        var failures = new List<PublishingFailure>();
   105→        int published = 0, skipped = 0;
   106→
   107→        foreach (var post in duePosts)
   108→        {
   109→            if (cancellationToken.IsCancellationRequested)
   110→            {
   111→                _logger.LogWarning("Publishing run aborted by cancellation request.");
   112→                break;
   113→            }
   114→
   115→            try
   116→            {
   117→                // Evaluate monetization rules before publishing. E.g., premium gating, tier checks, etc.
   118→                MonetizationDecision decision =
   119→                    await _monetizationRuleEvaluator
   120→                        .EvaluateAsync(post, cancellationToken)
   121→                        .ConfigureAwait(false);
   122→
   123→                if (decision == MonetizationDecision.DenyPublish)
   124→                {
   125→                    skipped++;
   126→                    _logger.LogInformation(
   127→                        "Post {PostId} skipped by monetization rule: {Reason}.",
   128→                        post.Id, decision.Reason);
   129→                    continue;
   130→                }
   131→
   132→                post.Publish(_clock.UtcNow);
   133→
   134→                // Persist state change through repository + UoW.
   135→                await _unitOfWork.SaveChangesAsync(cancellationToken).ConfigureAwait(false);
   136→
   137→                // Propagate domain events so adapters (email, webhooks, cache invalidation, etc.) can react.
   138→                await _eventDispatcher.DispatchAsync(post.PendingEvents, cancellationToken).ConfigureAwait(false);
   139→                post.ClearPendingEvents();
   140→
   141→                published++;
   142→                _logger.LogInformation("Post {PostId} successfully published.", post.Id);
   143→            }
   144→            catch (Exception ex)
   145→            {
   146→                failures.Add(new PublishingFailure(post.Id, ex.Message, ex));
   147→                _logger.LogError(ex, "Failed to publish post {PostId}.", post.Id);
   148→            }
   149→        }
   150→
   151→        var report = new PublishingReport(
   152→            TotalExamined       : duePosts.Count,
   153→            SuccessfullyPublished : published,
   154→            SkippedByRule       : skipped,
   155→            Failed              : failures.Count,
   156→            Failures            : failures);
   157→
   158→        _logger.LogInformation(
   159→            "Scheduled publishing run finished. Examined={Examined} Published={Published} Skipped={Skipped} Failed={Failed}",
   160→            report.TotalExamined, report.SuccessfullyPublished, report.SkippedByRule, report.Failed);
   161→
   162→        return report;
   163→    }
   164→}
